'use client'
import { cn } from '@cascivo/core'
import type { HTMLAttributes, ReactNode } from 'react'
import { Avatar } from '../avatar/avatar'
import type { AvatarProps } from '../avatar/avatar'
import styles from './user.module.css'

export interface UserProps extends HTMLAttributes<HTMLDivElement> {
  /** Primary identity label (name). */
  name: ReactNode
  /** Secondary line (email, role, …). */
  description?: ReactNode
  /** Forwarded to the composed <Avatar>. */
  avatarProps?: AvatarProps
  /** Optional trailing action slot (e.g. a menu button). */
  children?: ReactNode
}

/** Identity composite: an Avatar with a name + optional description and trailing action. */
export function User({ name, description, avatarProps, className, children, ...rest }: UserProps) {
  // Forward the string name to the Avatar so it derives initials (and labels the
  // image), unless the caller already set name/fallback via avatarProps. Spread
  // conditionally so we never pass an explicit `undefined` (exactOptionalPropertyTypes).
  const nameProp =
    typeof name === 'string' &&
    avatarProps?.name === undefined &&
    avatarProps?.fallback === undefined
      ? { name }
      : {}

  return (
    <div role="group" className={cn(styles['user'], className)} {...rest}>
      <Avatar {...nameProp} {...avatarProps} />
      <span className={styles['text']}>
        <span className={styles['name']}>{name}</span>
        {description != null && <span className={styles['description']}>{description}</span>}
      </span>
      {children != null && <span className={styles['action']}>{children}</span>}
    </div>
  )
}

@layer cascivo.component {
  .user {
    display: inline-flex;
    align-items: center;
    gap: var(--cascivo-space-3);
    min-inline-size: 0;
    font-family: var(--cascivo-font-sans);
  }

  .text {
    display: flex;
    flex-direction: column;
    min-inline-size: 0;
    line-height: var(--cascivo-leading-snug, 1.3);
  }

  .name {
    color: var(--cascivo-color-text);
    font-size: var(--cascivo-text-sm);
    font-weight: var(--cascivo-font-medium);
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }

  .description {
    color: var(--cascivo-color-text-muted);
    font-size: var(--cascivo-text-xs);
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }

  .action {
    display: inline-flex;
    align-items: center;
    margin-inline-start: var(--cascivo-space-2);
  }
}
